    java: 'class Solution {\n    public int cutRibbons(int[] ribbons, int k) {\n        int low = 1, high = 0;\n        for (int r : ribbons) {\n            if (r > high) {\n                high = r;\n            }\n        }\n        int res = 0;\n        while (low <= high) {\n            int mid = low + (high - low) / 2;\n            int cnt = 0;\n            for (int r : ribbons) {\n                cnt += r / mid;\n            }\n            if (cnt >= k) {\n                res = mid;\n                low = mid + 1;\n            } else {\n                high = mid - 1;\n            }\n        }\n        return res;\n    }\n}',
