      'from collections import deque\n\n\ndef racecar(target: int) -> int:\n    vis = {(0, 1)}\n    q = deque([(0, 1)])\n    steps = 0\n    while q:\n        steps += 1\n        for _ in range(len(q)):\n            pos, speed = q.popleft()\n            np, ns = pos + speed, speed * 2\n            if np == target:\n                return steps\n            if 0 < np < 2 * target and (np, ns) not in vis:\n                vis.add((np, ns))\n                q.append((np, ns))\n            rs = 1 if speed < 0 else -1\n            if (pos, rs) not in vis:\n                vis.add((pos, rs))\n                q.append((pos, rs))\n    return -1',
    java: 'import java.util.ArrayDeque;\nimport java.util.HashSet;\nimport java.util.Set;\n\nclass Solution {\n    public int racecar(int target) {\n        Set<Long> vis = new HashSet<>();\n        ArrayDeque<int[]> q = new ArrayDeque<>();\n        vis.add(key(0, 1));\n        q.add(new int[]{0, 1});\n        int steps = 0;\n        while (!q.isEmpty()) {\n            steps++;\n            int sz = q.size();\n            for (int i = 0; i < sz; i++) {\n                int[] cur = q.poll();\n                int pos = cur[0], speed = cur[1];\n                int np = pos + speed, ns = speed * 2;\n                if (np == target) {\n                    return steps;\n                }\n                if (np > 0 && np < 2 * target && !vis.contains(key(np, ns))) {\n                    vis.add(key(np, ns));\n                    q.add(new int[]{np, ns});\n                }\n                int rs = speed < 0 ? 1 : -1;\n                if (!vis.contains(key(pos, rs))) {\n                    vis.add(key(pos, rs));\n                    q.add(new int[]{pos, rs});\n                }\n            }\n        }\n        return -1;\n    }\n\n    private static long key(int a, int b) {\n        return ((long) a << 32) ^ (b & 0xffffffffL);\n    }\n}',
