      'def find_missing_in_ap(a):\n    n = len(a)\n    low, high = 0, n - 1\n    num = a[high] - a[low]\n    # Go integer division truncates toward zero\n    q = abs(num) // n\n    diff = q if num >= 0 else -q\n    while low <= high:\n        mid = low + (high - low) // 2\n        expected = a[0] + mid * diff\n        if a[mid] == expected:\n            low = mid + 1\n        else:\n            high = mid - 1\n    return a[0] + low * diff',
